command:
const tableName = "Battlefield Reactions";

const table = game.tables.getName(tableName);

if (!table) {
  ui.notifications.error(`RollTable "${tableName}" not found.`);
  return;
}

const roll = await table.roll();
const result = roll.results[0];

let content = `
<h2>🌋 Battlefield Reaction</h2>

<p>
<strong>[${result.range[0]}]</strong> ${result.text}
</p>
`;

ChatMessage.create({
  user: game.user.id,
  speaker: ChatMessage.getSpeaker(),
  content
});
